{
  "name": "image-flow",
  "displayName": "Image Flow",
  "version": "0.1.0",
  "description": "VS Code 扩展：在编辑器内对 Markdown 文件调用 AI 绘图后端生成图片",
  "publisher": "image-flow",
  "engines": {
    "vscode": "^1.85.0"
  },
  "activationEvents": [
    "onStartupFinished"
  ],
  "main": "./dist/extension.js",
  "contributes": {
    "viewsContainers": {
      "activitybar": [
        {
          "id": "image-flow",
          "title": "AI 绘图",
          "icon": "media/icon.svg"
        }
      ]
    },
    "views": {
      "image-flow": [
        {
          "id": "image-flow.sidebar",
          "name": "AI 绘图",
          "type": "webview"
        }
      ]
    },
    "commands": [
      {
        "command": "image-flow.generateImage",
        "title": "Image Flow: 生成 AI 图片"
      },
      {
        "command": "image-flow.previewRequest",
        "title": "Image Flow: 预览请求"
      }
    ],
    "menus": {
      "explorer/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ],
      "editor/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ]
    },
    "configuration": {
      "title": "Image Flow",
      "properties": {
        "image-flow.baseUrl": {
          "type": "string",
          "default": "https://grsai.dakka.com.cn",
          "description": "API 节点地址"
        },
        "image-flow.model": {
          "type": "string",
          "default": "nano-banana-2",
          "enum": [
            "nano-banana-2",
            "nano-banana-pro",
            "gpt-image-2",
            "gpt-image-2-vip"
          ],
          "description": "生成模型"
        },
        "image-flow.aspectRatio": {
          "type": "string",
          "default": "3:4",
          "enum": [
            "1:1",
            "16:9",
            "9:16",
            "4:3",
            "3:4"
          ],
          "description": "图片比例"
        },
        "image-flow.imageSize": {
          "type": "string",
          "default": "1K",
          "enum": [
            "1K",
            "2K",
            "4K"
          ],
          "description": "图片分辨率"
        },
        "image-flow.concurrency": {
          "type": "integer",
          "default": 1,
          "minimum": 1,
          "maximum": 10,
          "description": "一次生成的并发张数"
        },
        "image-flow.workbenchCols": {
          "type": "integer",
          "default": 4,
          "minimum": 1,
          "maximum": 8,
          "description": "工作台素材缩略图每行张数"
        },
        "image-flow.tasksCols": {
          "type": "integer",
          "default": 2,
          "minimum": 1,
          "maximum": 8,
          "description": "任务页缩略图每行张数"
        },
        "image-flow.modelInjections": {
          "type": "object",
          "default": {},
          "description": "模型 → 注入提示词的映射"
        }
      }
    }
  },
  "scripts": {
    "compile": "npm run check-types && npm run lint && node esbuild.main.mjs && node esbuild.webview.mjs",
    "watch": "node esbuild.main.mjs --watch",
    "package": "npm run compile && vsce package",
    "check-types": "tsc -p tsconfig.main.json --noEmit && tsc -p tsconfig.webview.json --noEmit",
    "lint": "eslint src/ media/ test/ --ext .ts,.tsx",
    "test": "tsc -p tsconfig.main.json --outDir out && tsc -p tsconfig.webview.json --outDir out && vscode-test"
  },
  "dependencies": {
    "@radix-ui/react-collapsible": "^1.1.2",
    "@radix-ui/react-progress": "^1.1.2",
    "@radix-ui/react-select": "^2.1.4",
    "@radix-ui/react-tabs": "^1.1.2",
    "react": "^19.0.0",
    "react-dom": "^19.0.0"
  },
  "devDependencies": {
    "@types/mocha": "^10.0.10",
    "@types/node": "^22.0.0",
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@types/vscode": "^1.85.0",
    "@typescript-eslint/eslint-plugin": "^8.0.0",
    "@typescript-eslint/parser": "^8.0.0",
    "@vscode/test-cli": "^0.0.10",
    "@vscode/test-electron": "^2.4.0",
    "esbuild": "^0.24.0",
    "eslint": "^9.0.0",
    "mocha": "^11.0.0",
    "typescript": "^5.7.0"
  }
}

import * as esbuild from 'esbuild';

const isWatch = process.argv.includes('--watch');

const ctx = await esbuild.context({
  entryPoints: ['src/extension.ts'],
  bundle: true,
  platform: 'node',
  format: 'cjs',
  external: ['vscode'],
  outfile: 'dist/extension.js',
  sourcemap: true,
  target: 'es2022',
});

if (isWatch) {
  await ctx.watch();
  console.log('[esbuild] 主进程 watching...');
} else {
  await ctx.rebuild();
  await ctx.dispose();
  console.log('[esbuild] 主进程构建完成 → dist/extension.js');
}

import * as esbuild from 'esbuild';

await esbuild.build({
  entryPoints: ['media/sidebar.tsx'],
  bundle: true,
  platform: 'browser',
  format: 'iife',
  globalName: 'ImageFlow',
  outfile: 'media/sidebar.js',
  sourcemap: false,
  target: 'es2022',
  minify: false,
});

console.log('[esbuild] webview 构建完成 → media/sidebar.js');

import tseslint from '@typescript-eslint/eslint-plugin';
import tsparser from '@typescript-eslint/parser';

export default [
  {
    ignores: ['dist/**', 'out/**', 'media/sidebar.js', 'node_modules/**'],
  },
  {
    files: ['src/**/*.ts', 'test/**/*.ts'],
    plugins: {
      '@typescript-eslint': tseslint,
    },
    languageOptions: {
      parser: tsparser,
      parserOptions: {
        ecmaVersion: 2022,
        sourceType: 'module',
      },
    },
    rules: {
      'no-unused-vars': 'off',
      '@typescript-eslint/no-unused-vars': ['warn', { argsIgnorePattern: '^_' }],
      'no-console': 'off',
    },
  },
  {
    files: ['media/**/*.tsx'],
    plugins: {
      '@typescript-eslint': tseslint,
    },
    languageOptions: {
      parser: tsparser,
      parserOptions: {
        ecmaVersion: 2022,
        sourceType: 'module',
        ecmaFeatures: { jsx: true },
      },
    },
    rules: {
      'no-unused-vars': 'off',
      '@typescript-eslint/no-unused-vars': ['warn', { argsIgnorePattern: '^_' }],
    },
  },
];

