/**
 * 生成流程 — 同步模式（M1）。
 * 读取 Markdown → 解析参考图 → 提交 API → 下载图片。
 */

import * as path from 'path';
import * as fs from 'fs';
import * as vscode from 'vscode';
import { parseMarkdown, isContentEmpty } from './markdown';
import { submitGenerate, buildRequestBody, downloadImage } from './api';
import { getConfig, getApiKey, getModelInjection } from './config';
import type { ExtensionConfig, TaskInfo, JobInfo } from './shared';
import { getImageExtension } from './utils';

/** 拼接最终提示词：注入句 + IMAGES.md + 替换后正文 */
function assemblePrompt(
  config: ExtensionConfig,
  body: string,
  workspaceRoot?: string,
): string {
  const parts: string[] = [];

  const injection = getModelInjection(config, config.model);
  if (injection.trim()) parts.push(injection.trim());

  if (workspaceRoot) {
    const imagesPath = path.join(workspaceRoot, 'IMAGES.md');
    try {
      const imagesContent = fs.readFileSync(imagesPath, 'utf-8').trim();
      if (imagesContent) parts.push(imagesContent);
    } catch { /* 不存在/无工作区静默跳过 */ }
  }

  if (body.trim()) parts.push(body.trim());

  return parts.join('\n\n');
}

// ─── 任务文件夹命名 ──────────────────────────────────

let taskSeqSec = '';
let taskSeqNum = 0;

function pad2(n: number): string {
  return String(n).padStart(2, '0');
}

function nextTaskFolderName(): string {
  const d = new Date();
  const yy = String(d.getFullYear()).slice(2);
  const sec = `${yy}${pad2(d.getMonth() + 1)}${pad2(d.getDate())}${pad2(d.getHours())}${pad2(d.getMinutes())}${pad2(d.getSeconds())}`;
  if (sec === taskSeqSec) {
    taskSeqNum++;
  } else {
    taskSeqSec = sec;
    taskSeqNum = 0;
  }
  return `task-${sec}-${taskSeqNum}`;
}

// ─── 主流程 ──────────────────────────────────────────

export async function generateImages(
  context: vscode.ExtensionContext,
  mdPath: string,
  sidebarProvider?: { postMessage(msg: object): void },
): Promise<void> {
  const config = getConfig(context);
  const apiKey = await getApiKey(context);

  if (!apiKey) {
    throw new Error('请先在设置页配置 API Key');
  }

  // 1. 读取 Markdown
  const content = fs.readFileSync(mdPath, 'utf-8');
  if (isContentEmpty(content)) {
    throw new Error('内容为空');
  }

  // 2. 解析参考图
  const mdDir = path.dirname(mdPath);
  const parseResult = parseMarkdown(content, mdDir);

  // 3. 拼接提示词
  const workspaceFolder = vscode.workspace.getWorkspaceFolder(vscode.Uri.file(mdPath));
  const workspaceRoot = workspaceFolder?.uri.fsPath;
  const finalPrompt = assemblePrompt(config, parseResult.body, workspaceRoot);

  // 4. 建任务文件夹
  const folderName = nextTaskFolderName();
  const taskDir = path.join(mdDir, folderName);
  fs.mkdirSync(taskDir, { recursive: true });

  const mdBaseName = path.basename(mdPath, '.md');
  const concurrency = Math.min(config.concurrency, 10);

  // 用于在多个 job 间接续图片编号
  let imageSeq = 1;
  const allImages: string[] = [];
  const allErrors: string[] = [];

  const jobs: JobInfo[] = [];
  for (let i = 0; i < concurrency; i++) {
    jobs.push({
      id: null,
      status: 'submitting',
      progress: 0,
      imagePaths: [],
      imageUris: [],
    });
  }

  // 通知侧栏任务开始
  sidebarProvider?.postMessage({
    type: 'statusMessage',
    text: `正在生成 ${folderName}…`,
    isError: false,
  });

  // 5. 并发提交并等待结果（同步模式 replyType: 'json'）
  const submitPromises = jobs.map(async (job) => {
    try {
      const body = buildRequestBody({
        model: config.model,
        prompt: finalPrompt,
        images: parseResult.refs.map(r => r.dataUri),
        aspectRatio: config.aspectRatio,
        imageSize: config.imageSize,
        replyType: 'json',
      });

      const resp = await submitGenerate(config.baseUrl, apiKey, body);

      if (resp.status === 'failed' || resp.status === 'violation') {
        job.status = resp.status;
        job.error = resp.error ?? resp.status;
        allErrors.push(job.error);
        return;
      }

      if (resp.status === 'succeeded' && resp.results) {
        job.status = 'succeeded';
        job.id = resp.id;
        // 6. 下载图片
        for (const r of resp.results) {
          const ext = getImageExtension(r.url);
          const fileName = `${mdBaseName}-${imageSeq}.${ext}`;
          const destPath = path.join(taskDir, fileName);
          await downloadImage(r.url, destPath);
          job.imagePaths.push(destPath);
          allImages.push(destPath);
          imageSeq++;
        }
      }
    } catch (err: unknown) {
      job.status = 'failed';
      job.error = String(err);
      allErrors.push(job.error);
    }
  });

  await Promise.all(submitPromises);

  // 7. 处理结果 — 全部失败则清理
  const allFailed = jobs.every(j => j.status !== 'succeeded');
  if (allFailed) {
    try { fs.rmdirSync(taskDir, { recursive: true }); } catch { /* ignore */ }
    const dedupedErrors = [...new Set(allErrors)].join('; ');
    vscode.window.showErrorMessage(`生成失败：${dedupedErrors}`);
    sidebarProvider?.postMessage({
      type: 'statusMessage',
      text: `生成失败：${dedupedErrors}`,
      isError: true,
    });
    return;
  }

  const failedJobs = jobs.filter(j => j.status !== 'succeeded');
  if (failedJobs.length > 0) {
    const dedupedErrors = [...new Set(failedJobs.map(j => j.error).filter(Boolean))].join('; ');
    vscode.window.showWarningMessage(`部分图片生成失败：${dedupedErrors}`);
  }

  sidebarProvider?.postMessage({
    type: 'statusMessage',
    text: `生成完成：${folderName}（${allImages.length} 张）`,
    isError: false,
  });
}

/**
 * 预览请求 — 与真实提交共用请求体构造，但不调 API。
 */

import * as path from 'path';
import * as fs from 'fs';
import * as vscode from 'vscode';
import { parseMarkdown, isContentEmpty } from './markdown';
import { buildRequestBody } from './api';
import { getConfig, getModelInjection } from './config';

function assemblePrompt(content: string, config: ReturnType<typeof getConfig>, workspaceRoot?: string): string {
  const parts: string[] = [];
  const injection = getModelInjection(config, config.model);
  if (injection.trim()) parts.push(injection.trim());
  if (workspaceRoot) {
    try {
      const imagesContent = fs.readFileSync(path.join(workspaceRoot, 'IMAGES.md'), 'utf-8').trim();
      if (imagesContent) parts.push(imagesContent);
    } catch { /* 静默跳过 */ }
  }
  if (content.trim()) parts.push(content.trim());
  return parts.join('\n\n');
}

export async function previewRequest(
  context: vscode.ExtensionContext,
  mdPath: string,
): Promise<void> {
  const config = getConfig(context);
  const content = fs.readFileSync(mdPath, 'utf-8');

  if (isContentEmpty(content)) {
    vscode.window.showErrorMessage('内容为空，无法预览');
    return;
  }

  const mdDir = path.dirname(mdPath);
  const parseResult = parseMarkdown(content, mdDir);
  const workspaceFolder = vscode.workspace.getWorkspaceFolder(vscode.Uri.file(mdPath));
  const finalPrompt = assemblePrompt(parseResult.body, config, workspaceFolder?.uri.fsPath);

  const requestBody = buildRequestBody({
    model: config.model,
    prompt: finalPrompt,
    images: parseResult.refs.map(r => r.dataUri),
    aspectRatio: config.aspectRatio,
    imageSize: config.imageSize,
    replyType: 'json',
  });

  const paramsForDisplay = { ...requestBody };
  delete paramsForDisplay.prompt;
  delete paramsForDisplay.images;

  const lines: string[] = [];
  lines.push('# 预览请求');
  lines.push('');
  lines.push('## 最终提示词');
  lines.push('');
  lines.push(finalPrompt);
  lines.push('');
  lines.push('## 请求地址');
  lines.push('');
  lines.push(`POST ${config.baseUrl}/v1/api/generate`);
  lines.push('');
  lines.push('## 请求参数（已剔除 prompt 与 images）');
  lines.push('');
  lines.push('```json');
  lines.push(JSON.stringify(paramsForDisplay, null, 2));
  lines.push('```');
  lines.push('');
  lines.push('## 参考图概览');
  lines.push('');

  if (parseResult.refs.length === 0) {
    lines.push('无参考图');
  } else {
    parseResult.refs.forEach((ref, i) => {
      const preview = ref.dataUri.slice(0, 48);
      lines.push(`- image${i + 1}: ${preview}…（${ref.dataUri.length} 字符）`);
    });
  }

  const doc = await vscode.workspace.openTextDocument({
    content: lines.join('\n'),
    language: 'markdown',
  });
  await vscode.window.showTextDocument(doc, { preview: true });
}

/**
 * 侧栏 Webview Provider — 管理 webview 生命周期与前后端通信。
 */

import * as vscode from 'vscode';
import type { ExtensionConfig, ExtensionMessage, WebviewMessage, ConfigUpdate } from './shared';
import { getConfig, updateConfig, getApiKey, setApiKey } from './config';
import { getNonce } from './utils';

export class SidebarProvider implements vscode.WebviewViewProvider {
  private view?: vscode.WebviewView;

  constructor(private readonly context: vscode.ExtensionContext) {}

  resolveWebviewView(webviewView: vscode.WebviewView): void {
    this.view = webviewView;

    const workspaceFolders = vscode.workspace.workspaceFolders?.map(f => f.uri) ?? [];
    webviewView.webview.options = {
      enableScripts: true,
      localResourceRoots: [this.context.extensionUri, ...workspaceFolders],
    };

    webviewView.webview.html = this.getHtml(webviewView.webview);

    webviewView.webview.onDidReceiveMessage((msg: WebviewMessage) => {
      this.handleMessage(msg);
    });
  }

  /** 刷新 localResourceRoots 以包含素材库与工作区目录 */
  updateLocalResourceRoots(): void {
    if (!this.view) return;
    const folders = vscode.workspace.workspaceFolders?.map(f => f.uri) ?? [];
    this.view.webview.options = {
      enableScripts: true,
      localResourceRoots: [this.context.extensionUri, ...folders],
    };
  }

  /** 向 webview 发消息 */
  postMessage(msg: ExtensionMessage): void {
    this.view?.webview.postMessage(msg);
  }

  /** 初始化下发全部状态 */
  async sendInitState(): Promise<void> {
    if (!this.view) return;
    const config = getConfig(this.context);
    const apiKey = await getApiKey(this.context);
    this.postMessage({
      type: 'config',
      data: { ...config, hasApiKey: apiKey.length > 0 },
    });
    this.postMessage({ type: 'activeMd', path: this.currentMdPath ?? '' });
    this.postMessage({ type: 'tasks', data: [] });
    this.postMessage({ type: 'history', data: [] });
  }

  // ─── 生效 MD 跟踪 ─────────────────────────────────

  private currentMdPath: string | undefined;

  setActiveMd(mdPath: string): void {
    this.currentMdPath = mdPath;
    this.postMessage({ type: 'activeMd', path: mdPath });
  }

  getActiveMd(): string | undefined {
    return this.currentMdPath;
  }

  // ─── 消息分发 ──────────────────────────────────────

  private async handleMessage(msg: WebviewMessage): Promise<void> {
    switch (msg.type) {
      case 'init':
        await this.sendInitState();
        break;

      case 'updateConfig':
        await updateConfig(this.context, msg.data);
        // 回传更新后的完整配置
        {
          const cfg = getConfig(this.context);
          const apiKey = await getApiKey(this.context);
          this.postMessage({ type: 'config', data: { ...cfg, hasApiKey: apiKey.length > 0 } });
        }
        break;

      case 'setApiKey':
        await setApiKey(this.context, msg.value);
        {
          const cfg = getConfig(this.context);
          this.postMessage({ type: 'config', data: { ...cfg, hasApiKey: msg.value.length > 0 } });
        }
        break;

      case 'generate':
        vscode.commands.executeCommand('image-flow.generateImage');
        break;

      case 'previewRequest':
        vscode.commands.executeCommand('image-flow.previewRequest');
        break;

      case 'openFile':
        try {
          const uri = vscode.Uri.file(msg.path);
          await vscode.commands.executeCommand('vscode.open', uri);
        } catch { /* ignore */ }
        break;

      case 'openExternal':
        await vscode.env.openExternal(vscode.Uri.parse(msg.url));
        break;

      case 'insertReference':
        // 仅当当前活动编辑器正是生效 MD 时才插入
        {
          const editor = vscode.window.activeTextEditor;
          if (!editor || !this.currentMdPath) {
            vscode.window.showWarningMessage('当前没有打开的 Markdown 文件');
            return;
          }
          if (editor.document.uri.fsPath !== this.currentMdPath) {
            vscode.window.showWarningMessage('活动编辑器与生效 MD 不一致，放弃插入');
            return;
          }
          const caret = editor.selection.active;
          const rel = this.makeRelativeRef(msg.path, path.dirname(this.currentMdPath));
          if (rel) {
            await editor.edit(eb => eb.insert(caret, rel));
          }
        }
        break;

      case 'pickMaterialFolder':
        {
          const folders = await vscode.window.showOpenDialog({
            canSelectFolders: true,
            canSelectFiles: false,
            canSelectMany: false,
          });
          if (folders && folders.length > 0) {
            this.postMessage({ type: 'allMaterialDirs', dirs: [folders[0].fsPath] });
          }
        }
        break;

      case 'removeMaterialFolder':
        // M4 实现
        break;
    }
  }

  // ─── 辅助 ──────────────────────────────────────────

  private makeRelativeRef(absPath: string, mdDir: string): string | null {
    const p = path.relative(mdDir, absPath).replace(/\\/g, '/');
    const name = path.basename(absPath, path.extname(absPath));
    const prefix = p.startsWith('..') ? '' : './';
    const refPath = p.includes(' ') || p.includes('(') || p.includes(')')
      ? `<${p}>` : p;
    return `![${name}](${prefix}${refPath})`;
  }

  // ─── HTML 生成 ─────────────────────────────────────

  private getHtml(webview: vscode.Webview): string {
    const scriptUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.context.extensionUri, 'media', 'sidebar.js'),
    );
    const styleUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.context.extensionUri, 'media', 'sidebar.css'),
    );
    const nonce = getNonce();

    return `<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta http-equiv="Content-Security-Policy"
    content="default-src 'none';
    img-src ${webview.cspSource} https: data:;
    style-src ${webview.cspSource} 'unsafe-inline';
    script-src 'nonce-${nonce}';">
  <link rel="stylesheet" href="${styleUri}">
  <title>AI 绘图</title>
</head>
<body>
  <div id="root"></div>
  <script nonce="${nonce}" src="${scriptUri}"></script>
</body>
</html>`;
  }
}

